# Minimal tool-use eval harness for model comparison
import json
from anthropic import Anthropic

TOOLS = [
    {
        "name": "search_database",
        "description": "Search the product database for items matching criteria",
        "input_schema": {
            "type": "object",
            "properties": {
                "query": {"type": "string"},
                "category": {"type": "string", "enum": ["electronics", "clothing", "books"]},
                "max_price": {"type": "number"}
            },
            "required": ["query"]
        }
    }
]

TEST_CASES = [
    {
        "prompt": "Find electronics under $50",
        "expected_tool": "search_database",
        "expected_params": {"category": "electronics", "max_price": 50},
    },
]

def score_tool_use(model_id: str, test_cases: list, client) -> dict:
    scores = []
    for tc in test_cases:
        resp = client.messages.create(
            model=model_id,
            max_tokens=512,
            tools=TOOLS,
            messages=[{"role": "user", "content": tc["prompt"]}]
        )
        tool_use = next((b for b in resp.content if b.type == "tool_use"), None)
        if tool_use is None:
            scores.append(0)
        elif tool_use.name != tc["expected_tool"]:
            scores.append(2)
        elif all(tool_use.input.get(k) == v for k, v in tc["expected_params"].items()):
            scores.append(5)
        else:
            scores.append(3)
    return {
        "model": model_id,
        "mean_score": sum(scores) / len(scores),
        "perfect_rate": sum(1 for s in scores if s == 5) / len(scores),
    }
